export const _modelCache: Map<string,{model:any, apiKey:string}> = new Map<string,{model:any, apiKey:string}>();

/**
 * Create AI SDK model instance from ApiConfig — routes to openai-compatible or anthropic provider. Cached by baseUrl+model+format; invalidated if API key changes.
 */
// @kern-source: dispatch:21
export function buildModel(config: ApiConfig): any {
  const apiKey = process.env[config.apiKeyEnv];
  if (!apiKey) return null;

  const cacheKey = `${config.baseUrl}|${config.model}|${config.format ?? 'openai'}`;
  const cached = _modelCache.get(cacheKey);
  if (cached && cached.apiKey === apiKey) return cached.model;

  const base = config.baseUrl.replace(/\/$/, '');

  let model: any;
  if (config.format === 'anthropic') {
    // createAnthropic baseURL should include /v1 — it appends /messages
    const baseURL = base.endsWith('/v1') ? base : base + '/v1';
    const provider = createAnthropic({ apiKey, baseURL });
    model = provider(config.model);
  } else {
    // OpenAI-compatible: baseURL is used as prefix, SDK appends /chat/completions
    const provider = createOpenAICompatible({
      name: 'agon-api',
      apiKey,
      baseURL: base,
    });
    model = provider.chatModel(config.model);
  }

  _modelCache.set(cacheKey, { model, apiKey });
  return model;
}

/**
 * Convert OpenAI-format tool definitions to AI SDK tool format.
 */
// @kern-source: dispatch:53
export function convertToolsForSdk(tools: Array<{type:string,function:{name:string,description:string,parameters:Record<string,unknown>}}>): Record<string,any> {
  const result: Record<string, any> = {};
  for (const t of tools) {
    result[t.function.name] = {
      description: t.function.description,
      inputSchema: jsonSchema(t.function.parameters as any),
      // No execute — tool execution is handled by the caller (persistent-session)
    };
  }
  return result;
}

/**
 * Normalize tool call IDs per provider: Anthropic requires [a-zA-Z0-9_], Mistral max 9 chars.
 */
// @kern-source: dispatch:67
function normalizeToolCallId(id: string, format?: string): string {
  if (!id) {
    return `call_${hostNowMs()}`;
  }
  if (format === 'anthropic') {
    // Claude: alphanumeric + underscore only
    return id.replace(/[^a-zA-Z0-9_]/g, '_');
  }
  // Mistral: max 9 chars, alphanumeric only
  if (format === 'mistral') {
    return id.replace(/[^a-zA-Z0-9]/g, '').slice(0, 9) || `c${hostNowMs() % 100000000}`;
  }
  return id;
}

/**
 * Convert Agon message history (OpenAI wire format) to AI SDK CoreMessage format. Handles per-provider normalization.
 */
// @kern-source: dispatch:80
export function convertMessagesForSdk(messages: Array<{role:string,content:any,tool_calls?:any[],tool_call_id?:string}>, format?: string): any[] {
  // Build original→normalized ID mapping, and record only immediately
  // following tool results for each assistant message. The AI SDK requires
  // every assistant tool-call part to be paired by the contiguous tool-result
  // block that follows it. If an interrupted stream left a dangling or
  // non-contiguous assistant tool_call in history, replay it as plain context
  // instead of letting the SDK throw MissingToolResultsError.
  const idMap = new Map<string, string>();
  for (const msg of messages) {
    if (msg.tool_calls) {
      for (const tc of msg.tool_calls) {
        if (tc.id && tc.function?.name) {
          const normalizedId = normalizeToolCallId(tc.id, format);
          idMap.set(tc.id, normalizedId);
        }
      }
    }
  }
  const contiguousResultIdsByAssistantIndex = new Map<number, Set<string>>();
  for (let i = 0; i < messages.length; i++) {
    const msg = messages[i] as any;
    if (msg?.role !== 'assistant' || !Array.isArray(msg.tool_calls) || msg.tool_calls.length === 0) continue;
    const resultIds = new Set<string>();
    for (let j = i + 1; j < messages.length; j++) {
      const candidate = messages[j] as any;
      if (candidate?.role !== 'tool') break;
      const originalId = typeof candidate.tool_call_id === 'string' ? candidate.tool_call_id : '';
      if (!originalId) continue;
      resultIds.add(idMap.get(originalId) ?? normalizeToolCallId(originalId, format));
    }
    contiguousResultIdsByAssistantIndex.set(i, resultIds);
  }

  const systemParts: string[] = [];
  for (const msg of messages) {
    if (msg.role !== 'system') continue;
    const content = typeof msg.content === 'string' ? msg.content : String(msg.content ?? '');
    if (content.trim()) systemParts.push(content);
  }

  const result: any[] = [];
  const activeToolNamesById = new Map<string, string>();
  if (systemParts.length > 0) {
    result.push({ role: 'system', content: systemParts.join('\n\n') });
  }
  const pushMessage = (message: any) => {
    const last = result[result.length - 1];
    if (
      message?.role === 'user'
      && last?.role === 'user'
      && typeof message.content === 'string'
      && typeof last.content === 'string'
    ) {
      last.content = `${last.content}\n\n${message.content}`;
      return;
    }
    result.push(message);
  };

  for (let messageIndex = 0; messageIndex < messages.length; messageIndex++) {
    const msg = messages[messageIndex];
    if (msg.role === 'system') {
      continue;
    } else if (msg.role === 'user') {
      // Multimodal user turns (text + {type:'image'} parts) pass through as an
      // array so the AI SDK forwards images to the provider; everything else is
      // coerced to a string. Array content is never merged (pushMessage only
      // merges string+string), so image parts stay intact.
      const userContent = Array.isArray(msg.content)
        ? msg.content
        : (typeof msg.content === 'string' ? msg.content : String(msg.content ?? ''));
      pushMessage({ role: 'user', content: userContent });
    } else if (msg.role === 'assistant') {
      const parts: any[] = [];
      if (msg.content && typeof msg.content === 'string') {
        parts.push({ type: 'text', text: msg.content });
      }
      if (msg.tool_calls) {
        const droppedToolCalls: string[] = [];
        const contiguousResultIds = contiguousResultIdsByAssistantIndex.get(messageIndex) ?? new Set<string>();
        for (const tc of msg.tool_calls) {
          let args: Record<string, unknown> = {};
          try {
            args = typeof tc.function?.arguments === 'string'
              ? JSON.parse(tc.function.arguments)
              : tc.function?.arguments ?? {};
          } catch { args = {}; /* malformed tool_calls JSON — use empty args */ }
          const normalizedId = idMap.get(tc.id) ?? normalizeToolCallId(tc.id ?? `call_${Date.now()}`, format);
          const toolName = tc.function?.name ?? 'unknown';
          if (!contiguousResultIds.has(normalizedId)) {
            droppedToolCalls.push(toolName);
            continue;
          }
          activeToolNamesById.set(normalizedId, toolName);
          parts.push({
            type: 'tool-call',
            toolCallId: normalizedId,
            toolName,
            input: args,
          });
        }
        if (droppedToolCalls.length > 0) {
          parts.push({
            type: 'text',
            text: `[Recovered incomplete tool call${droppedToolCalls.length > 1 ? 's' : ''} omitted from native tool channel: ${droppedToolCalls.join(', ')}]`,
          });
        }
      }
      if (parts.length > 0) {
        pushMessage({ role: 'assistant', content: parts });
      } else {
        pushMessage({ role: 'assistant', content: '' });
      }
    } else if (msg.role === 'tool') {
      const originalId = typeof (msg as any).tool_call_id === 'string' ? (msg as any).tool_call_id : '';
      const toolCallId = originalId ? (idMap.get(originalId) ?? normalizeToolCallId(originalId, format)) : '';
      const toolName = toolCallId ? activeToolNamesById.get(toolCallId) : undefined;
      const outputValue = typeof msg.content === 'string' ? msg.content : JSON.stringify(msg.content);
      if (!toolCallId || !toolName) {
        pushMessage({
          role: 'user',
          content: `[Recovered orphan tool result omitted from native tool channel]\n${outputValue}`,
        });
      } else {
        pushMessage({
          role: 'tool',
          content: [{
            type: 'tool-result',
            toolCallId,
            toolName,
            output: {
              type: 'text' as const,
              value: outputValue,
            },
          }],
        });
        activeToolNamesById.delete(toolCallId);
      }
    }
  }

  // Mistral quirk: needs a dummy assistant message after consecutive tool results
  if (format === 'mistral') {
    for (let i = 1; i < result.length; i++) {
      if (result[i].role === 'tool' && result[i - 1].role === 'tool') {
        result.splice(i, 0, { role: 'assistant', content: '' });
        i++;
      }
    }
  }

  return result;
}

// @kern-source: dispatch:236
export async function apiDispatch(config: ApiConfig, prompt: string, timeout: number, signal?: AbortSignal, systemPrompt?: string): Promise<DispatchResult> {
  const model = buildModel(config);
  if (!model) {
    return {
      exitCode: 1,
      stdout: '',
      stderr: `Missing API key: set ${config.apiKeyEnv} environment variable`,
      durationMs: 0,
      timedOut: false,
    };
  }

  const startTime = Date.now();
  const messages: Array<{role: 'system'|'user', content: string}> = [];
  if (systemPrompt) messages.push({ role: 'system', content: systemPrompt });
  messages.push({ role: 'user', content: prompt });

  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), timeout * 1000);
  if (signal) {
    if (signal.aborted) { clearTimeout(timer); return { exitCode: 130, stdout: '', stderr: 'Aborted', durationMs: 0, timedOut: false }; }
    signal.addEventListener('abort', () => controller.abort(), { once: true });
  }

  try {
    const result = await generateText({
      model,
      messages,
      maxOutputTokens: config.maxTokens ?? 4096,
      abortSignal: controller.signal,
      maxRetries: 5,
    });
    clearTimeout(timer);
    const text = result.text || '';
    const usage = result.usage ? {
      promptTokens: result.usage.inputTokens ?? 0,
      completionTokens: result.usage.outputTokens ?? 0,
      totalTokens: (result.usage.inputTokens ?? 0) + (result.usage.outputTokens ?? 0),
      cachedInputTokens: result.usage.cachedInputTokens ?? 0,
      source: 'sdk' as const,
    } : undefined;
    return { exitCode: 0, stdout: text, stderr: '', durationMs: Date.now() - startTime, timedOut: false, usage };
  } catch (err) {
    clearTimeout(timer);
    const durationMs = Date.now() - startTime;
    if (err instanceof Error && err.name === 'AbortError') {
      return { exitCode: signal?.aborted ? 130 : 124, stdout: '', stderr: 'Request timed out', durationMs, timedOut: !signal?.aborted };
    }
    const isRateLimited = err instanceof Error && (
      err.message.includes('429') || err.message.includes('rate') || err.name === 'AI_RetryError' || err.name === 'RetryError'
    );
    const exitCode = isRateLimited ? 2 : 1;
    const prefix = isRateLimited ? 'API rate limited (retries exhausted)' : 'API request failed';
    return { exitCode, stdout: '', stderr: `${prefix}: ${err instanceof Error ? err.message : String(err)}`, durationMs, timedOut: false };
  }
}

export async function* apiStreamDispatch(config: ApiConfig, prompt: string, timeout: number, signal?: AbortSignal, systemPrompt?: string): AsyncGenerator<string, DispatchResult, void> {
  const messages: Array<{role:string, content:string}> = [];
  if (systemPrompt) {
    messages.push({ role: 'system', content: systemPrompt });
  }
  messages.push({ role: 'user', content: prompt });
  return yield * apiStreamDispatchWithHistory(config, messages, timeout, signal);
}

// @kern-source: dispatch:302
export async function apiDispatchToolsHistory(config: ApiConfig, messages: Array<{role:string,content:any,tool_calls?:any[],tool_call_id?:string}>, timeout: number, signal?: AbortSignal, tools?: Array<{type:string,function:{name:string,description:string,parameters:Record<string,unknown>}}>, systemPrompt?: string): Promise<DispatchResult> {
  // Non-streaming NATIVE function-calling over a FULL message history. Phase 2: the browser
  // brain reconstructs a proper assistant/tool thread each step (instead of re-sending a flat
  // text transcript as one user prompt), so the model attends to a real tool conversation and
  // the stable prefix can be prompt-cached. Optionally prepends a system message. Drains the
  // streaming dispatch to its final DispatchResult (any structured tool_call lands in .parts)
  // and disposes the underlying SSE stream if we exit early via a throw from gen.next() (the
  // inner generator normally catches its own errors and RETURNS, so the happy path falls out
  // of the loop and return() is a no-op on the finished generator).
  const full = systemPrompt ? [{ role: 'system', content: systemPrompt }, ...messages] : messages;
  const gen = apiStreamDispatchWithHistory(config, full, timeout, signal, tools);
  try {
    while (true) {
      const next = await gen.next();
      if (next.done) return next.value;
    }
  } finally {
    try { await gen.return(undefined as unknown as DispatchResult); } catch { /* best-effort disposal */ }
  }
}

// @kern-source: dispatch:324
export async function apiDispatchTools(config: ApiConfig, prompt: string, timeout: number, signal?: AbortSignal, tools?: Array<{type:string,function:{name:string,description:string,parameters:Record<string,unknown>}}>, systemPrompt?: string): Promise<DispatchResult> {
  // Single-prompt convenience over apiDispatchToolsHistory, for callers with no conversation
  // thread (Phase 1 path): one user message + optional system. The browser brain instead passes
  // a full reconstructed history via apiDispatchToolsHistory (Phase 2). Trailing optional args are
  // (tools?, systemPrompt?) — the SAME order as apiDispatchToolsHistory and apiStreamDispatchWithHistory,
  // so the three tool-aware dispatchers never silently swap systemPrompt and tools.
  return apiDispatchToolsHistory(config, [{ role: 'user', content: prompt }], timeout, signal, tools, systemPrompt);
}

// @kern-source: dispatch:340
export const _formatHintEmitted: Set<string> = new Set<string>();

/**
 * Detect a common misconfiguration: format='anthropic' on a non-Anthropic base URL. Moonshot/Kimi/Groq/Together/DeepInfra etc. claim Anthropic compatibility loosely but actually serve OpenAI-shaped /chat/completions. Returns a one-line hint the first time we hit it for a given host, then null on subsequent calls for that host.
 */
// @kern-source: dispatch:342
function formatMismatchHint(config: ApiConfig): string|null {
  if (config.format !== 'anthropic') {
    return null;
  }
  try {
    const host = hostUrlHost(config.baseUrl).toLowerCase();
    if (host === 'api.anthropic.com' || host.endsWith('.anthropic.com')) {
      return null;
    }
    if (_formatHintEmitted.has(host)) {
      return null;
    }
    _formatHintEmitted.add(host);
    return `tip: format='anthropic' on '${host}' — many OpenAI-compat providers (Moonshot/Kimi, Groq, Together, DeepInfra) claim Anthropic but serve OpenAI /chat/completions. Try format='openai' (or remove the field) in the engine config.`;
  } catch (e) {
    return null;
  }
}

/**
 * Streaming dispatch with full message history + optional native function calling. Uses Vercel AI SDK for robust SSE handling and provider abstraction.
 */
export async function* apiStreamDispatchWithHistory(config: ApiConfig, messages: Array<{role:string,content:any,tool_calls?:any[],tool_call_id?:string}>, timeout: number, signal?: AbortSignal, tools?: Array<{type:string,function:{name:string,description:string,parameters:Record<string,unknown>}}>): AsyncGenerator<string, DispatchResult, void> {
  const model = buildModel(config);
  if (!model) {
    return { exitCode: 1, stdout: '', stderr: `Missing API key: set ${config.apiKeyEnv}`, durationMs: 0, timedOut: false };
  }

  const startTime = Date.now();

  // Convert messages to AI SDK CoreMessage format
  // Detect provider format for per-provider normalization
  const providerFormat = config.format === 'anthropic' ? 'anthropic'
    : config.baseUrl?.includes('mistral') ? 'mistral'
    : undefined;
  const coreMessages = convertMessagesForSdk(messages, providerFormat);

  // Set up timeout + external abort
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), timeout * 1000);
  if (signal) {
    if (signal.aborted) { clearTimeout(timer); return { exitCode: 130, stdout: '', stderr: 'Aborted', durationMs: 0, timedOut: false }; }
    signal.addEventListener('abort', () => controller.abort(), { once: true });
  }

  let stdout = '';
  // Capture structured parts at stream time — compaction folds over these
  // instead of doing fragile regex extraction on flat text
  const capturedParts: Array<{kind:'text',text:string}|{kind:'reasoning',text:string}|{kind:'tool_call',toolName:string,toolCallId:string,args:Record<string,unknown>}> = [];
  let currentTextBuf = '';
  let currentReasoningBuf = '';

  try {
    const streamOpts: any = {
      model,
      messages: coreMessages,
      maxOutputTokens: config.maxTokens ?? 4096,
      abortSignal: controller.signal,
      maxRetries: 5,
    };

    if (tools && tools.length > 0) {
      streamOpts.tools = convertToolsForSdk(tools);
    }

    // Apply Anthropic cache control: mark system + last 2 messages as ephemeral
    // This saves input tokens on multi-turn conversations
    if (config.format === 'anthropic' && coreMessages.length > 0) {
      // Cache system prompt (stable across turns)
      for (const msg of coreMessages) {
        if ((msg as any).role === 'system') {
          (msg as any).experimental_providerMetadata = {
            anthropic: { cacheControl: { type: 'ephemeral' } },
          };
          break;
        }
      }
      // Cache last 2 user/assistant messages (recent context)
      let cached = 0;
      for (let i = coreMessages.length - 1; i >= 0 && cached < 2; i--) {
        const role = (coreMessages[i] as any).role;
        if (role === 'user' || role === 'assistant') {
          (coreMessages[i] as any).experimental_providerMetadata = {
            anthropic: { cacheControl: { type: 'ephemeral' } },
          };
          cached++;
        }
      }
    }

    const result = streamText(streamOpts);

    // Two-tier idle timeout: longer patience before first chunk (queuing/cold start),
    // tighter watchdog once streaming starts. Per-engine config overrides defaults.
    // IDLE_TIMEOUT was 15s, which killed API engines during silent reasoning or
    // tool-call phases — a real failure mode observed in agon forge where gemini,
    // kimi-for-coding, and zai-coding produced zero diff because their stream
    // went quiet for >15s while internally working. 90s gives coding engines
    // room to think without breaking the safety net for genuinely hung streams.
    const FIRST_CHUNK_TIMEOUT = config.firstChunkTimeoutMs ?? 60_000;  // 60s default
    const IDLE_TIMEOUT = config.idleTimeoutMs ?? 90_000;              // 90s default
    const iterator = result.fullStream[Symbol.asyncIterator]();
    let iterDone = false;
    let gotFirstChunk = false;
    let chunkCount = 0;
    // AI SDK fullStream 'finish' part carries finishReason ('stop'|'length'|
    // 'content-filter'|...). Surfaced on the success return so callers can name
    // reasoning-exhaustion ('length' + empty stdout: the model spent its whole
    // output budget thinking) instead of misreporting a generic empty response.
    let finishReason: string | undefined;

    while (!iterDone) {
      const timeoutMs = gotFirstChunk ? IDLE_TIMEOUT : FIRST_CHUNK_TIMEOUT;
      const next = iterator.next();
      const idle = new Promise<never>((_, reject) => {
        const t = setTimeout(() => reject(new Error('IDLE_TIMEOUT')), timeoutMs);
        next.then(() => clearTimeout(t), () => clearTimeout(t));
      });

      let iterResult: IteratorResult<any>;
      try {
        iterResult = await Promise.race([next, idle]);
      } catch (err: any) {
        if (err?.message === 'IDLE_TIMEOUT') {
          const phase = gotFirstChunk ? 'inter-chunk' : 'first-chunk';
          console.warn(`[agon] api-dispatch: ${phase} idle timeout (${timeoutMs / 1000}s) — breaking stream`);
          // First-chunk timeout on a non-Anthropic host using Anthropic format is almost
          // always a config mismatch — surface the hint via stderr so the session UI picks it up.
          if (!gotFirstChunk) {
            const hint = formatMismatchHint(config);
            if (hint) {
              clearTimeout(timer);
              controller.abort();
              return { exitCode: 1, stdout, stderr: `API first-chunk timeout (${timeoutMs / 1000}s). ${hint}`, durationMs: Date.now() - startTime, timedOut: true };
            }
          }
          // No format-mismatch hint (or already past the first chunk) — this is a
          // genuine stalled/hung stream. NEVER fall through to the success return
          // below: a timeout must never be indistinguishable from a successful
          // empty answer (the double-swallowed-error bug — see runReviewCore in
          // review.kern, which used to re-report this as "parse-failure: empty or
          // unusable response" instead of the real timeout).
          clearTimeout(timer);
          controller.abort();
          const reasoningCharsSoFar = capturedParts.filter((p) => p.kind === 'reasoning').reduce((n, p: any) => n + p.text.length, 0) + currentReasoningBuf.length;
          if (currentTextBuf) { capturedParts.push({ kind: 'text', text: currentTextBuf }); currentTextBuf = ''; }
          if (currentReasoningBuf) { capturedParts.push({ kind: 'reasoning', text: currentReasoningBuf }); currentReasoningBuf = ''; }
          const reasoningInfo = reasoningCharsSoFar > 0 ? `, ${reasoningCharsSoFar} reasoning chars` : '';
          return {
            exitCode: 124,
            stdout,
            stderr: `API stream ${phase} idle timeout after ${timeoutMs / 1000}s (received ${chunkCount} chunks, ${stdout.length} text chars${reasoningInfo})`,
            durationMs: Date.now() - startTime,
            timedOut: true,
            parts: capturedParts,
          };
        }
        throw err;
      }

      if (iterResult.done) { iterDone = true; break; }
      const part = iterResult.value;
      chunkCount++;

      // Any productive event switches to tighter inter-chunk timeout
      if (!gotFirstChunk && (part.type === 'text-delta' || part.type === 'reasoning-delta' || part.type === 'tool-call')) {
        gotFirstChunk = true;
      }

      switch (part.type) {
        case 'text-delta': {
          const text = (part as any).text;
          stdout += text;
          currentTextBuf += text;
          yield text;
          break;
        }
        case 'reasoning-delta': {
          const text = (part as any).delta ?? '';
          if (text) {
            currentReasoningBuf += text;
          }
          break;
        }
        case 'tool-call': {
          // Flush accumulated text/reasoning buffers as parts
          if (currentTextBuf) {
            capturedParts.push({ kind: 'text', text: currentTextBuf });
            currentTextBuf = '';
          }
          if (currentReasoningBuf) {
            capturedParts.push({ kind: 'reasoning', text: currentReasoningBuf });
            currentReasoningBuf = '';
          }
          // Capture tool call as structured part
          const toolName = (part as any).toolName ?? 'unknown';
          const toolCallId = (part as any).toolCallId ?? `call_${Date.now()}`;
          const toolInput = (part as any).input ?? {};
          capturedParts.push({ kind: 'tool_call', toolName, toolCallId, args: toolInput });

          // Emit as <tool> marker matching Agon's parseToolCalls regex
          const marker = `\n<tool name="${toolName}">${JSON.stringify(toolInput)}</tool>\n`;
          stdout += marker;
          yield marker;
          break;
        }
        case 'error': {
          clearTimeout(timer);
          const errStr = String((part as any).error);
          // A 404/not-found before any output is almost always a wrong baseUrl
          // path or a wire-format mismatch (e.g. format='anthropic' on a host
          // whose Anthropic endpoint isn't at /v1/messages — MiniMax, etc.).
          // Surface the actionable hint inline so the user sees the fix rather
          // than a bare 404. (Same hint the idle-timeout + catch paths use.)
          // NOTE: deliberately narrower than brain.kern's deterministic-retry
          // classifier (which also matches 401/403/auth). The format hint says
          // "try format='openai'", which is right for a wrong-path/format 404
          // but MISLEADING on a genuine auth 401 — those already get brain.kern's
          // "check /engines" hint instead. Do NOT broaden this to auth codes.
          const routingShaped = stdout.length === 0 && /\b404\b|not found|no such (?:route|endpoint)/i.test(errStr);
          const hint = routingShaped ? formatMismatchHint(config) : null;
          return { exitCode: 1, stdout, stderr: hint ? `Stream error: ${errStr}\n${hint}` : `Stream error: ${errStr}`, durationMs: Date.now() - startTime, timedOut: false };
        }
        case 'finish': {
          // AI SDK TextStreamPart: { type: 'finish', finishReason, totalUsage }.
          // 'length' means the model hit maxOutputTokens — with empty stdout that
          // is reasoning exhaustion (all budget spent thinking), which callers
          // must be able to name.
          const fr = (part as any).finishReason;
          if (typeof fr === 'string' && fr) finishReason = fr;
          break;
        }
      }
    }

    // Flush final text/reasoning buffers
    if (currentTextBuf) capturedParts.push({ kind: 'text', text: currentTextBuf });
    if (currentReasoningBuf) capturedParts.push({ kind: 'reasoning', text: currentReasoningBuf });

    clearTimeout(timer);

    let usage: DispatchResult['usage'] = undefined;
    try {
      const finalUsage = await (result as any).usage;
      if (finalUsage) {
        usage = {
          promptTokens: finalUsage.inputTokens ?? 0,
          completionTokens: finalUsage.outputTokens ?? 0,
          totalTokens: (finalUsage.inputTokens ?? 0) + (finalUsage.outputTokens ?? 0),
          cachedInputTokens: finalUsage.cachedInputTokens ?? 0,
          source: 'sdk' as const,
        };
      }
    } catch { /* usage tokens optional — extraction failure is non-critical */ }
    return { exitCode: 0, stdout, stderr: '', durationMs: Date.now() - startTime, timedOut: false, usage, parts: capturedParts, finishReason };
  } catch (err) {
    clearTimeout(timer);
    const durationMs = Date.now() - startTime;
    if (err instanceof Error && err.name === 'AbortError') {
      return { exitCode: signal?.aborted ? 130 : 124, stdout, stderr: 'Request timed out', durationMs, timedOut: !signal?.aborted };
    }
    const isRateLimited = err instanceof Error && (
      err.message.includes('429') || err.message.includes('rate') || err.name === 'AI_RetryError' || err.name === 'RetryError'
    );
    const exitCode = isRateLimited ? 2 : 1;
    const prefix = isRateLimited ? 'API rate limited (retries exhausted)' : 'API stream failed';
    const baseMsg = `${prefix}: ${err instanceof Error ? err.message : String(err)}`;
    // Anthropic-format on non-Anthropic host is a common misconfig — append a hint
    // so the user sees it in the error toast instead of silently falling back every turn.
    const hint = stdout.length === 0 && !isRateLimited ? formatMismatchHint(config) : null;
    return { exitCode, stdout, stderr: hint ? `${baseMsg}\n${hint}` : baseMsg, durationMs, timedOut: false };
  }
}
